// Merge items from both triggers
const items = $input.all();
return items.map(item => ({
  json: {
    raw_content: item.json.contentSnippet || item.json.content || item.json.body || '',
    source: item.json.creator || item.json.author || 'MuftiWP',
  }
})).filter(i => i.json.raw_content.length > 30);

const items = $input.all();
const results = [];

for (const item of items) {
  try {
    // Parse Gemini response
    let text = item.json.text || item.json.content || '';
    // Strip markdown code blocks if present
    text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const parsed = JSON.parse(text);

    // Generate SHA256 hash
    const encoder = new TextEncoder();
    const data = encoder.encode(parsed.content);
    const hashBuffer = await crypto.subtle.digest('SHA-256', data);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    const hash = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');

    const source = $('Normalize Input').item.json.source || 'MuftiWP';

    results.push({
      json: {
        content: parsed.content,
        source: source,
        category: parsed.category,
        language: parsed.language || 'ms',
        content_hash: hash,
      }
    });
  } catch (e) {
    // Skip malformed responses
    continue;
  }
}

return results;

const items = $input.all();
const results = { created: 0, duplicate: 0, error: 0 };

for (const item of items) {
  const status = item.json.statusCode || 200;
  if (status === 201) results.created++;
  else if (status === 409) results.duplicate++;
  else results.error++;
}

console.log(`Qalbu ingest: +${results.created} new | ${results.duplicate} dup | ${results.error} err`);
return [{ json: results }];
